+import type { CodeReviewPrState } from '../../hooks/useApi';
+
+/**
+ * Map a PR state to the design-system Badge variant. Shared between the
+ * pulls list and the per-PR detail page so the colour mapping stays in
+ * one place.
+ */
+export function prStateBadgeVariant(
+  state: CodeReviewPrState,
+): 'success' | 'info' | 'error' {
+  if (state === 'open') return 'success';
+  if (state === 'merged') return 'info';
+  return 'error';
+}
